import os
import hashlib
import json
import logging
from pathlib import Path
from google.cloud import storage

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)


def verify_checksum(file_path: str, expected_sha256: str) -> bool:
    sha256 = hashlib.sha256()
    with open(file_path, "rb") as f:
        for chunk in iter(lambda: f.read(8192), b""):
            sha256.update(chunk)
    return sha256.hexdigest() == expected_sha256


def load_model_from_gcs(
    bucket_name: str,
    model_prefix: str,
    local_cache_dir: str = "/tmp/models",
):
    """
    Downloads the latest model version from GCS, verifies its SHA-256
    checksum against a manifest, then loads it.
    
    Expects a manifest.json in the model prefix with:
    {"version": "v3", "filename": "model.onnx", "sha256": "abc123..."}
    """
    client = storage.Client()
    bucket = client.bucket(bucket_name)
    
    # Download manifest
    manifest_blob = bucket.blob(f"{model_prefix}/manifest.json")
    manifest_data = json.loads(manifest_blob.download_as_text())
    
    version = manifest_data["version"]
    filename = manifest_data["filename"]
    expected_sha256 = manifest_data["sha256"]
    
    logger.info(f"Latest model version: {version}, file: {filename}")
    
    local_dir = Path(local_cache_dir) / version
    local_dir.mkdir(parents=True, exist_ok=True)
    local_path = local_dir / filename
    
    if not local_path.exists() or not verify_checksum(str(local_path), expected_sha256):
        logger.info(f"Downloading model {version} from gs://{bucket_name}/{model_prefix}/{version}/{filename}")
        blob = bucket.blob(f"{model_prefix}/{version}/{filename}")
        blob.download_to_filename(str(local_path))
    
    # Verify checksum after download
    if not verify_checksum(str(local_path), expected_sha256):
        local_path.unlink()
        raise RuntimeError(
            f"Checksum mismatch for {filename}. Expected {expected_sha256}. "
            "The model file may have been tampered with. Aborting."
        )
    
    logger.info(f"Checksum verified for model {version}")
    
    # Use ONNX Runtime (safe) instead of pickle (unsafe)
    import onnxruntime as ort
    session = ort.InferenceSession(str(local_path))
    logger.info(f"Model {version} loaded successfully")
    return session, manifest_data


if __name__ == "__main__":
    model_gcs_path = os.environ.get("MODEL_GCS_PATH", "my-bucket/models/my-model")
    parts = model_gcs_path.split("/", 1)
    bucket_name, prefix = parts[0], parts[1]
    
    model, metadata = load_model_from_gcs(bucket_name, prefix)
    logger.info(f"Serving model version: {metadata['version']}")